module.render:
const type = (args.type || 'rectangle').toLowerCase();
const fill = args.fill || 'var(--accent-color)';
const bw = args.borderwidth || '0';
const bc = args.bordercolor || 'var(--border-color)';
const tc = args.textcolor || '#ffffff';
const fs = args.fontsize || '1em';
const h = (args.halign || 'center').toLowerCase();
const v = (args.valign || 'middle').toLowerCase();
const justify = h === 'left' ? 'flex-start' : h === 'right' ? 'flex-end' : 'center';
const alignItems = v === 'top' ? 'flex-start' : v === 'bottom' ? 'flex-end' : 'center';
const textAlign = h === 'left' ? 'left' : h === 'right' ? 'right' : 'center';
const bodyStr = sections[0] ? sections[0].trim() : '';

// Regular n-gon / star point strings in a 0..100 viewBox (centred at 50,50).
const ngon = function (n, r, rot) {
  const p = [];
  for (let i = 0; i < n; i++) {
    const a = rot + (i * 2 * Math.PI) / n;
    p.push((50 + r * Math.cos(a)).toFixed(2) + ',' + (50 + r * Math.sin(a)).toFixed(2));
  }
  return p.join(' ');
};
const starPts = function (n, ro, ri, rot) {
  const p = [];
  for (let i = 0; i < n * 2; i++) {
    const r = i % 2 === 0 ? ro : ri;
    const a = rot + (i * Math.PI) / n;
    p.push((50 + r * Math.cos(a)).toFixed(2) + ',' + (50 + r * Math.sin(a)).toFixed(2));
  }
  return p.join(' ');
};
const top = -Math.PI / 2; // first vertex at the top
const common = `fill="${fill}" stroke="${bc}" stroke-width="${bw}" vector-effect="non-scaling-stroke" stroke-linejoin="round"`;
// Fill the viewBox edge-to-edge so the shape hugs its box (and the selection
// frame). The SVG uses overflow:visible + non-scaling-stroke, so any border
// straddles the edge instead of being clipped.
let inner;
if (type === 'ellipse') {
  inner = `<ellipse cx="50" cy="50" rx="50" ry="50" ${common}/>`;
} else if (type === 'rectangle' || type === 'rect' || type === 'square') {
  inner = `<rect x="0" y="0" width="100" height="100" ${common}/>`;
} else {
  let pts;
  if (type === 'triangle') pts = '50,0 100,100 0,100';
  else if (type === 'diamond') pts = '50,0 100,50 50,100 0,50';
  else if (type === 'pentagon') pts = ngon(5, 50, top);
  else if (type === 'hexagon') pts = ngon(6, 50, top);
  else if (type === 'star') pts = starPts(5, 50, 21, top);
  else pts = '0,0 100,0 100,100 0,100';
  inner = `<polygon points="${pts}" ${common}/>`;
}
const svg = `<svg class="mdp-shape-svg" viewBox="0 0 100 100" preserveAspectRatio="none">${inner}</svg>`;
const textOpen = `<div class="mdp-shape-text" style="color: ${tc}; font-size: ${fs}; justify-content: ${justify}; align-items: ${alignItems}; text-align: ${textAlign};">`;
// Blank lines around the content so markdown renders it inside the text layer.
return `\n\n<div class="mdp-mod-shape">${svg}${textOpen}\n\n${bodyStr}\n\n</div></div>\n\n`;
